import { useState, useEffect } from 'react';
import { Badge, Modal, Field, Input, Select, Btn, useToast, Toast } from '../components/UI';
import { DEMO_ORDERS, DEMO_RIDERS, timeAgo, apiCall } from '../utils';

export default function AdminOrders({ token }) {
  const [orders, setOrders] = useState([]);
  const [riders, setRiders] = useState([]);
  const [statusFilter, setStatusFilter] = useState('');
  const [assignModal, setAssignModal] = useState(null); // { orderId, trackingId }
  const [selectedRider, setSelectedRider] = useState('');
  const [toast, showToast] = useToast();

  useEffect(() => { loadOrders(); loadRiders(); }, [statusFilter]);

  async function loadOrders() {
    try {
      const data = await apiCall(`/orders${statusFilter?'?status='+statusFilter:''}`, token);
      if (data.success && data.orders?.length) setOrders(data.orders);
      else setOrders(statusFilter ? DEMO_ORDERS.filter(o=>o.status===statusFilter) : DEMO_ORDERS);
    } catch { setOrders(statusFilter ? DEMO_ORDERS.filter(o=>o.status===statusFilter) : DEMO_ORDERS); }
  }

  async function loadRiders() {
    try {
      const data = await apiCall('/riders', token);
      setRiders(data.riders || DEMO_RIDERS);
    } catch { setRiders(DEMO_RIDERS); }
  }

  async function submitAssign() {
    if (!selectedRider) { showToast('Please select a rider', 'error'); return; }
    try {
      const data = await apiCall(`/orders/${assignModal.orderId}/assign`, token, { method:'PUT', body: JSON.stringify({ rider_id: selectedRider }) });
      if (data.success) { showToast('Rider assigned successfully!', 'success'); setAssignModal(null); loadOrders(); }
      else showToast(data.message||'Error', 'error');
    } catch {
      showToast('Demo: Rider assigned!', 'success');
      setAssignModal(null);
      setOrders(prev => prev.map(o => o.id === assignModal.orderId ? {...o, status:'assigned'} : o));
    }
  }

  const statuses = ['','pending','assigned','picked_up','out_for_delivery','delivered','failed','returned'];

  return (
    <div style={{padding:28}}>
      <Toast {...toast}/>

      {/* Filter bar */}
      <div style={{display:'flex',gap:8,marginBottom:20,flexWrap:'wrap'}}>
        {statuses.map(s=>(
          <button key={s} onClick={()=>setStatusFilter(s)} style={{
            padding:'7px 16px',borderRadius:99,fontSize:12,fontWeight:600,cursor:'pointer',
            background: statusFilter===s ? 'rgba(59,130,246,.25)' : 'rgba(255,255,255,.05)',
            border: statusFilter===s ? '1px solid rgba(59,130,246,.4)' : '1px solid rgba(255,255,255,.08)',
            color: statusFilter===s ? '#93c5fd' : 'rgba(255,255,255,.4)',
            transition:'all .15s',
          }}>{s || 'All Statuses'}</button>
        ))}
      </div>

      <div style={{background:'rgba(255,255,255,.04)',border:'1px solid rgba(255,255,255,.08)',borderRadius:16,overflow:'hidden'}}>
        <div style={{padding:'18px 22px',borderBottom:'1px solid rgba(255,255,255,.07)'}}>
          <div style={{fontSize:15,fontWeight:700,color:'#f1f5f9'}}>All Orders</div>
          <div style={{fontSize:12,color:'rgba(255,255,255,.3)',marginTop:2}}>{orders.length} order{orders.length!==1?'s':''}</div>
        </div>
        <div style={{overflowX:'auto'}}>
          <table style={{width:'100%',borderCollapse:'collapse'}}>
            <thead>
              <tr>
                {['Tracking ID','Customer','Merchant','Rider','Zone','COD','Charge','Status','Action'].map(h=>(
                  <th key={h} style={{textAlign:'left',padding:'11px 18px',fontSize:11,fontWeight:600,color:'rgba(255,255,255,.3)',textTransform:'uppercase',letterSpacing:'.06em',borderBottom:'1px solid rgba(255,255,255,.07)',background:'rgba(0,0,0,.2)',whiteSpace:'nowrap'}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {orders.length === 0 ? (
                <tr><td colSpan={9}><div style={{textAlign:'center',padding:'60px 20px',color:'rgba(255,255,255,.2)',fontSize:14}}>📭 No orders found</div></td></tr>
              ) : orders.map((o,i)=>(
                <tr key={i}
                  onMouseEnter={e=>e.currentTarget.style.background='rgba(255,255,255,.03)'}
                  onMouseLeave={e=>e.currentTarget.style.background='transparent'}
                  style={{borderBottom:'1px solid rgba(255,255,255,.05)'}}
                >
                  <td style={{padding:'13px 18px'}}><span style={{fontFamily:'DM Mono,monospace',fontSize:12,color:'#60a5fa'}}>{o.tracking_id}</span></td>
                  <td style={{padding:'13px 18px'}}>
                    <div style={{fontSize:13,fontWeight:600,color:'#e2e8f0'}}>{o.customer_name}</div>
                    <div style={{fontSize:11,color:'rgba(255,255,255,.3)'}}>{o.customer_phone}</div>
                  </td>
                  <td style={{padding:'13px 18px',fontSize:13,color:'rgba(255,255,255,.6)'}}>{o.merchant_name||'—'}</td>
                  <td style={{padding:'13px 18px',fontSize:13,color: o.rider_name?'rgba(255,255,255,.6)':'rgba(255,255,255,.25)'}}>{o.rider_name||'Unassigned'}</td>
                  <td style={{padding:'13px 18px',fontSize:13,color:'rgba(255,255,255,.6)'}}>{o.zone_name||'—'}</td>
                  <td style={{padding:'13px 18px',fontFamily:'DM Mono,monospace',fontSize:13,fontWeight:600,color:'#fbbf24'}}>৳{Number(o.cod_amount||0).toLocaleString()}</td>
                  <td style={{padding:'13px 18px',fontFamily:'DM Mono,monospace',fontSize:13,fontWeight:600,color:'#34d399'}}>৳{Number(o.delivery_charge||0).toLocaleString()}</td>
                  <td style={{padding:'13px 18px'}}><Badge status={o.status}/></td>
                  <td style={{padding:'13px 18px'}}>
                    {o.status==='pending' ? (
                      <button onClick={()=>{setAssignModal({orderId:o.id,trackingId:o.tracking_id});setSelectedRider('');}} style={{
                        background:'rgba(59,130,246,.2)',border:'1px solid rgba(59,130,246,.4)',
                        color:'#93c5fd',borderRadius:8,padding:'5px 12px',fontSize:12,fontWeight:600,cursor:'pointer',
                      }}>Assign →</button>
                    ) : <span style={{color:'rgba(255,255,255,.2)',fontSize:12}}>—</span>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Assign Modal */}
      <Modal open={!!assignModal} onClose={()=>setAssignModal(null)}
        title="Assign Rider"
        subtitle={`Assigning order: ${assignModal?.trackingId}`}
      >
        <div style={{['--modal-bg']:'#1a1f2c',['--modal-border']:'rgba(255,255,255,.1)',['--modal-text']:'#f1f5f9',['--modal-sub']:'rgba(255,255,255,.4)',['--input-border']:'rgba(255,255,255,.12)',['--input-bg']:'rgba(255,255,255,.06)',['--input-text']:'#f1f5f9',['--label-color']:'rgba(255,255,255,.4)'}}>
          <Field label="Select Rider">
            <select value={selectedRider} onChange={e=>setSelectedRider(e.target.value)}
              style={{width:'100%',padding:'10px 13px',background:'rgba(255,255,255,.06)',border:'1.5px solid rgba(255,255,255,.12)',borderRadius:10,fontSize:13,color:'#f1f5f9',outline:'none'}}>
              <option value="">Choose available rider…</option>
              {riders.filter(r=>r.status==='online').map(r=>(
                <option key={r.id} value={r.id}>
                  {r.name} — ৳{Number(r.current_cash||0).toLocaleString()} / ৳{Number(r.cod_limit||0).toLocaleString()} cash
                </option>
              ))}
            </select>
          </Field>
          <div style={{display:'flex',gap:10,marginTop:24,justifyContent:'flex-end'}}>
            <button onClick={()=>setAssignModal(null)} style={{padding:'10px 20px',borderRadius:10,background:'rgba(255,255,255,.06)',border:'1px solid rgba(255,255,255,.12)',color:'rgba(255,255,255,.6)',cursor:'pointer',fontSize:13,fontWeight:600}}>Cancel</button>
            <button onClick={submitAssign} style={{padding:'10px 20px',borderRadius:10,background:'linear-gradient(135deg,#2563eb,#4f46e5)',color:'#fff',border:'none',cursor:'pointer',fontSize:13,fontWeight:600}}>Assign Rider</button>
          </div>
        </div>
      </Modal>
    </div>
  );
}
